record.field:
today = fields.Date.context_today(model)
cutoff = today + datetime.timedelta(days=30)
expiring = model.search([
    ('license_expiry', '!=', False),
    ('license_expiry', '>=', today),
    ('license_expiry', '<=', cutoff),
])
if expiring:
    template = env.ref('transit_ops.mail_template_license_expiry', raise_if_not_found=False)
    safety_group = env.ref('transit_ops.group_transit_safety_officer', raise_if_not_found=False)
    if template and safety_group:
        for user in safety_group.users:
            if user.email:
                template.with_context(
                    expiring_drivers=expiring,
                    recipient_email=user.email,
                    recipient_name=user.name,
                ).send_mail(expiring[0].id, force_send=True, email_values={'email_to': user.email})
